You can copy the code below, save it as an `.html` file (e.g., `house.html`), and open it in any modern web browser to see the 3D model.

### 3D House Generator (Three.js)

This code creates a simple house with a roof, walls, a door, and a window, complete with lighting and shadows.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: Arial, sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click and drag to rotate • Scroll to zoom</div>

    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 3. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(50, 50, 50);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. Create the House
        const houseGroup = new THREE.Group();

        // Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0xA52A2A }); // Dark Red
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x333333 }); // Dark Grey
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x87CEEB, transparent: true, opacity: 0.5 });

        // Floor
        const floorGeometry = new THREE.BoxGeometry(20, 1, 20);
        const floor = new THREE.Mesh(floorGeometry, new THREE.MeshStandardMaterial({ color: 0x228B22 })); // Grass
        floor.position.y = -1;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Walls
        const wallGeometry = new THREE.BoxGeometry(10, 6, 10);
        const walls = new THREE.Mesh(wallGeometry, wallMaterial);
        walls.position.y = 3;
        walls.castShadow = true;
        walls.receiveShadow = true;
        houseGroup.add(walls);

        // Roof
        const roofGeometry = new THREE.ConeGeometry(9, 4, 4);
        const roof = new THREE.Mesh(roofGeometry, roofMaterial);
        roof.position.y = 8;
        roof.rotation.y = Math.PI / 4; // Rotate to align with walls
        roof.castShadow = true;
        houseGroup.add(roof);

        // Door
        const doorGeometry = new THREE.BoxGeometry(2, 4, 0.5);
        const door = new THREE.Mesh(doorGeometry, doorMaterial);
        door.position.set(0, 2, 5); // Front center
        door.castShadow = true;
        houseGroup.add(door);

        // Window
        const windowGeometry = new THREE.BoxGeometry(2, 2, 0.5);
        const windowMesh = new THREE.Mesh(windowGeometry, windowMaterial);
        windowMesh.position.set(0, 5, 5); // Top right
        windowMesh.castShadow = true;
        houseGroup.add(windowMesh);

        // Add House to Scene
        scene.add(houseGroup);

        // 5. Ground Grid (Optional visual aid)
        const gridHelper = new THREE.GridHelper(100, 20, 0x000000, 0x000000);
        gridHelper.position.y = 0.1;
        gridHelper.material.opacity = 0.1;
        gridHelper.material.transparent = true;
        scene.add(gridHelper);

        // 6. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Window Resize
        window.addEventListener('resize', onWindowResize, false);
        function onWindowResize() {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        }

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  **Copy** the code block above.
2.  Create a new file on your computer named `house.html`.
3.  **Paste** the code into that file and save it.
4.  **Double-click** `house.html` to open it in your web browser (Chrome, Firefox, Safari, Edge).

### What this code does:
*   **Sets up a 3D Scene:** Creates a virtual world with a sky-blue background and fog.
*   **Builds Geometry:** Constructs a house using basic shapes (Box for walls/floor, Cone for the roof).
*   **Adds Details:** Includes a door, a window, and a grassy floor.
*   **Lighting & Shadows:** Adds directional light to cast realistic shadows and ambient light to illuminate the scene.
*   **Interactivity:** Uses `OrbitControls` so you can click and drag to rotate around the house and scroll to zoom in/out.
